import React, { Component } from 'react';
import { Link } from 'react-router-dom';
import './savedcity.css';

class SavedCity extends Component {

    renderCityBlock = (param) => {

        if (param.length > 0) {
            return (param.map((item, index) => {
                return (
                    <div key={index} className='overlay'>
                        <Link to={`/cities/${item}`} className='saved-cities-block'>
                            <p className='saved-cities-block__name'>{item}</p>
                        </Link>
                    </div>
                )
            }))
        } else {
            return (<div></div>)
        }
    }

    render() {
        const { city } = this.props;

        return (
            <>
                <div className="saved-cities">
                    <div className='saved-cities__title'>Saved cities</div>
                    <div className='saved-cities__blocks'>
                        {this.renderCityBlock(city)}
                    </div>
                </div>
            </>
        );
    }
}

export default SavedCity;