import React, { Component } from 'react';
import OpenWeatherMapService from '../../services/openWeatherMap-service';
import './fullweather.css';
import Moment from 'react-moment';
import 'moment-timezone';
import { withRouter } from 'react-router-dom';


class FullWeather extends Component {
    openweather = new OpenWeatherMapService();

    state = {
        humidity: null,
        pressure: null,
        temp: null,
        temp_max: null,
        temp_min: null,
        sunrise: null,
        sunset: null,
        visibility: null,
        description: null,
        icon: null,
        speed: null,
    }

    componentDidMount( ) {
        const { cityId } = this.props;

        this.openweather
            .getFullCityWeather(cityId)
            .then((response) => {
                this.setState({
                    humidity: response.main.humidity,
                    pressure: response.main.pressure,
                    temp: response.main.temp,
                    temp_max: response.main.temp_max,
                    temp_min: response.main.temp_min,
                    sunrise: response.sys.sunrise,
                    sunset: response.sys.sunset,
                    visibility: response.visibility,
                    description: response.weather[0].description,
                    icon: response.weather[0].icon,
                    speed: response.wind.speed,
                })
                console.log(response);
            });
    }

    render() {
        const { humidity, pressure, temp, temp_max, temp_min, sunrise, sunset, visibility, description, icon, speed } = this.state;
        return (
            <>
                <div className='fullweather'>
                    <p className='fullweather__desc'>Полный прогноз на день</p>
                    <div className='fullweather__title'>{this.props.cityId}</div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Влажность: </span>
                        <span>{humidity} %</span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Давление: </span>
                        <span>{pressure} hpa</span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Температура: </span>
                        <span>{temp} ℃</span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Максимальная температура: </span>
                        <span>{temp_max} ℃</span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Минимальная температура: </span>
                        <span> {temp_min} ℃</span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Восход: </span>
                        <span>
                            <Moment format="HH:MM">
                                {sunrise}
                            </Moment>
                        </span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Закат: </span>
                        <span>
                            <Moment format="HH:MM">
                                {sunset}
                            </Moment>
                        </span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Видимость: </span>
                        <span> {visibility}</span>
                    </div>

                    <img className="weather-widget__img" src={`https://openweathermap.org/img/w/${icon}.png`} alt='Weather' width="50" height="50"></img>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Скорость ветра: </span>
                        <span>{speed}</span>
                    </div>

                    <div className='fullweather-block'>
                        <span className='fullweather-block__text'>Описание погоды: </span>
                        <span>{description}</span>
                    </div>

                </div>
            </>
        )
    }
}

export default withRouter(FullWeather);