import React, { Component } from 'react';
import './currentcity.css';
import OpenWeatherMapService from '../../services/openWeatherMap-service';
import GeoPosition from '../../services/position-service';



class CurrentCity extends Component {
    openweather = new OpenWeatherMapService();
    opengeo = new GeoPosition();

    onBtnClick = () => {
        const { namecity} = this.props.currentcity;
        this.props.saveCity(namecity);
    }

    componentWillMount = () => {
        this.opengeo.getPosition()
            .then((position) => {
                this.openweather
                    .getCityWeather(position)
                    .then((responce) => this.props.currentCity(responce));
            })
            .catch((err) => {
                console.error(err.message);
            });
    }

    getWeatherSelectedCity = (param) => {
        console.log('работает?');
        this.openweather
            .getFullCityWeather(param)
            .then();
    }


    render() {
        const { namecity, temperature, windspeed, cloudiness } = this.props.currentcity;
        return (
            <>
                <div className="current-city">
                    <div className='current-city__temperature'>{temperature} °C</div>
                    <div className='current-city__city'>{namecity}</div>
                    <div className='current-city__other'>{cloudiness}, Wind - {windspeed} meter per second</div>

                    <button
                        className='add-city'
                        onClick={this.onBtnClick}
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 31.059 31.059">
                            <path d="M15.529 31.059C6.966 31.059 0 24.092 0 15.529 0 6.966 6.966 0 15.529 0c8.563 0 15.529 6.966 15.529 15.529.001 8.563-6.966 15.53-15.529 15.53zm0-29.285c-7.585 0-13.755 6.171-13.755 13.755s6.17 13.754 13.755 13.754c7.584 0 13.754-6.17 13.754-13.754S23.113 1.774 15.529 1.774z" fill="#95989a" />
                            <path d="M21.652 16.416H9.406a.887.887 0 1 1 0-1.775h12.246a.888.888 0 0 1 0 1.775z" fill="#95989a" />
                            <path d="M15.529 22.539a.888.888 0 0 1-.888-.887V9.406a.889.889 0 0 1 1.775 0v12.246a.886.886 0 0 1-.887.887z" fill="#95989a" />
                        </svg>
                    </button>
                </div>
            </>
        );
    }
}

export default CurrentCity;



