export default class OpenWeatherMapService {

    _apiBase = 'https://api.openweathermap.org/data/2.5/';
    _apikey = '9dfd2dfdd6ba75c4621f310ef166019a';

    getWeather = async () => {
        const api_call = await fetch(`${this._apiBase}weather?q=london,uk&appid=${this._apikey}`);
        const response = await api_call.json();
        return response;
    }

    getCityWeather = async (position) => {
        const api_call = await fetch(`${this._apiBase}weather?lat=${position.coords.latitude}&lon=${position.coords.longitude}&units=metric&appid=${this._apikey}`);
        const response = await api_call.json();
        return response;
    }

    getTodayWeather = async (positionNameCity) => {
        const api_call = await fetch(`${this._apiBase}forecast?q=${positionNameCity}&units=metric&cnt=5&appid=${this._apikey}`);
        const response = await api_call.json();
        return response;
    }
    
    getTomorrowWeatherForecast = async (positionNameCity) => {
        const api_call = await fetch(`${this._apiBase}forecast?q=${positionNameCity}&units=metric&cnt=13&appid=${this._apikey}`);
        const response = await api_call.json();
        return response;
    }

    getFullCityWeather = async (cityname) => {
        const api_call = await fetch(`${this._apiBase}weather?q=${cityname}&units=metric&appid=${this._apikey}`);
        const response = await api_call.json();
        return response;
    }
}