import React, { Component } from 'react';
import './header.css';
import Search from '../Search';
import { Link } from 'react-router-dom';

class Header extends Component {
    render() {
        const{saveSelectedCity } = this.props;
        return (
            <div className="header">
                    <ul className='days'>
                        <li>
                            <Link to="/today" className='days__link'>Today</Link>
                        </li>
                        <li>
                            <Link to="/tomorrow" className='days__link'>Tommorow</Link>
                        </li>
                        <li>
                            <Link to="/" className='days__link'>Home</Link>
                        </li>
                    </ul>

                {/*   <input className='input' type="text" name="City" id="autocomplete" placeholder='Find city...' /> */}

                <Search saveSelectedCity={saveSelectedCity} />

            </div>
        );
    }
}

export default Header;