import React, { Component } from 'react';
import { BrowserRouter as Router, Route } from 'react-router-dom';
import { connect } from 'react-redux';
import './App.css';
import Header from './components/Header';
import CurrentCity from './components/CurrentCity';
import SavedCity from './components/SavedCity';
import Today from './components/Today';
import Tomorrow from './components/Tomorrow';
import FullWeather from './components/FullWeather';
import { saveCity } from './actions/saveCityActions';
import { saveSelectedCity } from './actions/selectedCityActions';
import { currentCity } from './actions/currentCityActions';


class App extends Component {
    render() {
        const { savedCity, setCityAction, setSaveAction, setCurrentAction, currentCity } = this.props;
        return (
            <>
                <Router>
                    <div className="App">
                        <Header saveSelectedCity={setCityAction} />
                        <CurrentCity
                            currentcity={currentCity}
                            saveCity={setSaveAction}
                            currentCity={setCurrentAction}
                        />

                        <Route exact path='/' render={() => <SavedCity city={savedCity} />} />
                        <Route path='/today' render={() => <Today locName={currentCity} />} />
                        <Route path='/tomorrow' render={() => <Tomorrow locName={currentCity} />} />
                        <Route
                            path='/cities/:id'
                            render={({ match }) => {
                                const { id } = match.params;
                                return <FullWeather cityId={id} />
                            }} />
                    </div>
                </Router>
            </>
        );
    }
}


const mapStateToProps = store => {
    return {
        savedCity: store.savedCity,
        selectedCity: store.selectedCity,
        currentCity: store.currentCity,
    }
}

const mapDispatchToProps = dispatch => {
    return {
        setSaveAction: city => dispatch(saveCity(city)),
        setCityAction: city => dispatch(saveSelectedCity(city)),
        setCurrentAction: responce => dispatch(currentCity(responce)),
    }
}

export default connect(mapStateToProps, mapDispatchToProps)(App)
