const initialState = {
    namecity: null,
    temperature: null,
    windspeed: null,
    cloudiness: null,
};

export function currentCityReducer(state = initialState, action) {
    switch (action.type) {
        case 'SET_CURRENTCITY':
            return {
                ...state,
                namecity: action.payload.name,
                temperature: action.payload.main.temp,
                windspeed: action.payload.wind.speed,
                cloudiness: action.payload.weather[0].description,
            };
        default:
            return state
    }
}