import React, { Component } from 'react';
import './today.css';
import OpenWeatherMapService from '../../services/openWeatherMap-service';
import Tabledata from '../Tabledata';
import Moment from 'react-moment';
import 'moment-timezone';
import Spinner from '../Spinner';

class Today extends Component {
    openweather = new OpenWeatherMapService();

    state = {
        data: null,
        days: null,
        lat: -28.643387,
        lng: 153.612224,
    }

    componentDidMount() {
        const { namecity } = this.props.locName;

        if (namecity) {
            this.openweather
                .getTodayWeather(namecity)
                .then((response) => {
                    this.setState(() => {
                        return {
                            data: response.list[0].dt_txt,
                            days: response.list,
                        }
                    })
                });
        }
    }

    renderTable(days) {
        return days.map((item, index) => {
            return (
                <Tabledata
                    data={item}
                    key={index}
                />
            )
        })
    }

    render() {
        const { data, days } = this.state;

        if (!days) {
            return (
                <Spinner />
            )
        }

        const table = this.renderTable(days);

        return (
            <div className='today'>
                <div className='today__data'>
                    <h3 className='today__title'>Today</h3>
                    <p className='today__data'>
                        <Moment format="MMMM, DD">
                            {data}
                        </Moment>
                    </p>

                    <table className='today-table'>
                        <thead>
                            <tr>
                                <th>Time</th>
                                <th>Weather</th>
                            </tr>
                        </thead>
                        <tbody>
                            {table}
                        </tbody>
                    </table>

                    <div id='map'></div>
                </div>
            </div>
        )
    }
}

export default Today;